Recent changes: Added countNeighbors helper and survival logic (keep cells with 2 or 3 neighbors).

Current implementation:
```typescript
type Cell = [number, number];

const countNeighbors = (cell: Cell, cells: Cell[]): number =>
  cells.filter(
    ([cx, cy]) =>
      Math.abs(cx - cell[0]) <= 1 &&
      Math.abs(cy - cell[1]) <= 1 &&
      !(cx === cell[0] && cy === cell[1])
  ).length;

export function nextGeneration(cells: Cell[]): Cell[] {
  return cells.filter((cell) => {
    const n = countNeighbors(cell, cells);
    return n === 2 || n === 3;
  });
}
```

